const items = $input.all();
const fundData = $('Determine Routing & Payload').first().json || {};
const agentData = $('Financial Orchestrator Agent').first().json || {};
const query = $('Validate Query Input').first().json.query;

// ---------- helpers ----------
const sanitize = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

// For markdown bodies we must NOT HTML-escape (it would break rendering).
// Only strip obviously dangerous script blocks.
const cleanMarkdown = (value) => String(value ?? '')
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .trim();

const truncate = (value, max = 1200) => {
  const text = String(value ?? '').trim();
  if (!text) return '';
  return text.length > max ? `${text.slice(0, max - 1).trimEnd()}…` : text;
};

const toNumber = (value) => {
  if (value === null || value === undefined || value === '') return null;
  const cleaned = String(value).replace(/[^0-9.+-]/g, '');
  if (!cleaned) return null;
  const parsed = Number(cleaned);
  return Number.isFinite(parsed) ? parsed : null;
};

// Pull "<number>%" that appears shortly after any of the label patterns.
const pctFromText = (text, patterns) => {
  const src = String(text ?? '');
  for (const p of patterns) {
    const re = new RegExp(p + '[^\\d\\n%+-]{0,18}(-?\\d+(?:\\.\\d+)?)\\s*%', 'i');
    const m = src.match(re);
    if (m) return parseFloat(m[1]);
  }
  return null;
};

// Pull a bare number that appears shortly after any of the label patterns.
const numFromText = (text, patterns) => {
  const src = String(text ?? '');
  for (const p of patterns) {
    const re = new RegExp(p + '[^\\d\\n+-]{0,18}(-?\\d+(?:\\.\\d+)?)', 'i');
    const m = src.match(re);
    if (m) return parseFloat(m[1]);
  }
  return null;
};

const fmtPct = (parsed, fallbackStructured) => {
  if (parsed !== null && parsed !== undefined) return `${parsed.toFixed(2)}%`;
  const n = toNumber(fallbackStructured);
  if (n === null) return 'N/A';
  const adj = Math.abs(n) <= 1 ? n * 100 : n;
  return `${adj.toFixed(2)}%`;
};

const fmtDec = (parsed, fallbackStructured, digits = 2) => {
  if (parsed !== null && parsed !== undefined) return parsed.toFixed(digits);
  const n = toNumber(fallbackStructured);
  return n === null ? 'N/A' : n.toFixed(digits);
};

// Return the text under a heading/label until the next markdown heading.
const sectionAfter = (text, headingRegex) => {
  const lines = String(text ?? '').split(/\r?\n/);
  let capturing = false;
  const out = [];
  for (const line of lines) {
    if (!capturing) {
      if (headingRegex.test(line)) capturing = true;
      continue;
    }
    if (/^\s*#{1,6}\s/.test(line)) break; // next heading ends the section
    out.push(line);
  }
  return out.join('\n').trim();
};

// ---------- source text ----------
const agentOutput = cleanMarkdown(
  agentData.output ?? agentData.text ?? agentData.response ?? agentData.result ?? ''
);

// ---------- scalar fields ----------
const fundName = sanitize(fundData.scheme_name || fundData.name || 'Unknown Fund');
const isin = sanitize(fundData.isin || 'N/A');
const amcName = sanitize(fundData.amc_name || 'N/A');
const category = sanitize(fundData.category || 'General');
const aum = (() => { const n = toNumber(fundData.aum); return n === null ? 'N/A' : n.toFixed(2); })();
const expenseRatio = (() => {
  const n = toNumber(fundData.expense_ratio);
  if (n === null) return 'N/A';
  const adj = Math.abs(n) <= 1 ? n * 100 : n;
  return `${adj.toFixed(2)}%`;
})();

const riskMetrics = fundData.data?.risk_metrics || {};
const holdings = Array.isArray(fundData.data?.holdings) ? fundData.data.holdings : [];
const navHistory = Array.isArray(fundData.data?.nav_history) ? fundData.data.nav_history : [];
const navWindow = navHistory.length >= 2
  ? `${sanitize(navHistory[0]?.date || 'N/A')} → ${sanitize(navHistory[navHistory.length - 1]?.date || 'N/A')}`
  : 'N/A';

const topHoldings = holdings.slice(0, 5).map((holding, index) => {
  const name = sanitize(holding.security || holding.name || holding.company || `Holding ${index + 1}`);
  const wRaw = holding.weight ?? holding.percentage ?? holding.pct ?? holding.holding_pct ?? holding.allocation;
  const wNum = toNumber(wRaw);
  const weight = wNum === null ? 'N/A' : `${(Math.abs(wNum) <= 1 ? wNum * 100 : wNum).toFixed(2)}%`;
  return `${index + 1}. ${name} (${weight})`;
});
const topHoldingsMarkdown = topHoldings.length > 0
  ? topHoldings.map((line) => `- ${line}`).join('\n')
  : '- None available from the current data layer.';
const topHoldingsSlack = topHoldings.length > 0
  ? topHoldings.map((line) => `• ${line}`).join('\n')
  : '• None available from the current data layer.';

// ---------- parsed performance / risk metrics (from analyst markdown) ----------
const cagr1y = fmtPct(pctFromText(agentOutput, ['1[\\s-]*years?', '1[\\s-]*yr', 'cagr[\\s-]*1y', '\\b1y\\b']), riskMetrics.cagr_1y);
const cagr3y = fmtPct(pctFromText(agentOutput, ['3[\\s-]*years?', '3[\\s-]*yr', 'cagr[\\s-]*3y', '\\b3y\\b']), riskMetrics.cagr_3y);
const cagr5y = fmtPct(pctFromText(agentOutput, ['5[\\s-]*years?', '5[\\s-]*yr', 'cagr[\\s-]*5y', '\\b5y\\b']), riskMetrics.cagr_5y);

const stdDev = fmtPct(
  pctFromText(agentOutput, ['annualized volatility', 'standard deviation', 'std\\.?\\s*dev', 'volatility']),
  riskMetrics.std_dev
);
const sharpe = fmtDec(numFromText(agentOutput, ['sharpe ratio', 'sharpe']), riskMetrics.sharpe, 2);
const beta = fmtDec(numFromText(agentOutput, ['\\bbeta\\b']), riskMetrics.beta, 2);
const maxDrawdown = fmtPct(pctFromText(agentOutput, ['maximum drawdown', 'max\\.?\\s*drawdown', 'drawdown']), null);

// ---------- narrative sections (markdown preserved, not collapsed) ----------
const paragraphs = agentOutput.split(/\n\s*\n/).map((s) => s.trim()).filter(Boolean);
let execSummary = '';
for (const para of paragraphs) {
  const isHeadingOnly = /^#{1,6}\s/.test(para) && !para.includes('\n');
  if (isHeadingOnly) continue; // skip standalone title/heading lines
  const cleaned = para.replace(/[#*`>_\-]/g, '').replace(/\s+/g, ' ').trim();
  if (cleaned.length > 60) { execSummary = para.replace(/^#{1,6}\s*/, '').trim(); break; }
}
if (!execSummary) execSummary = 'No executive summary was produced.';

let recommendation =
  sectionAfter(agentOutput, /(^|\s)#{0,6}\s*.*conclusion/i) ||
  sectionAfter(agentOutput, /(recommendation|trade\s*\/\s*reallocation|reallocation approval)/i);
if (!recommendation) {
  recommendation = paragraphs.length ? paragraphs[paragraphs.length - 1] : 'No recommendation was produced.';
}
recommendation = truncate(cleanMarkdown(recommendation), 4000);

const detailedAnalysis = agentOutput || '_No analyst output was returned._';

// ---------- risk flags / HITL ----------
const stdDevNumeric = toNumber(stdDev);
const sharpeNumeric = toNumber(sharpe);
const riskFlags = [];
if (stdDevNumeric !== null && stdDevNumeric >= 22) riskFlags.push('High volatility');
if (sharpeNumeric !== null && sharpeNumeric < 0.5) riskFlags.push('Weak risk-adjusted returns');
if (navHistory.length < 20) riskFlags.push('Limited NAV history for deeper analysis');
const riskFlagText = riskFlags.length > 0 ? riskFlags.join(', ') : 'No active risk flags';
const hitlStatus = riskFlags.includes('High volatility') ? 'APPROVED' : 'DIRECT_ACTION';

// ---------- assemble report markdown ----------
const reportMarkdown = `# Mutual Fund Investment Report: ${fundName}

## Executive Summary
${execSummary}

## Fund Profile
- **ISIN**: ${isin} | **AMC**: ${amcName}
- **Category**: ${category} | **Total AUM**: ${aum} Lakhs
- **Expense Ratio**: ${expenseRatio}

## Performance Metrics
- **1-Year CAGR**: ${cagr1y}
- **3-Year CAGR**: ${cagr3y}
- **5-Year CAGR**: ${cagr5y}

## Risk & Volatility Analysis
- **Standard Deviation**: ${stdDev}
- **Sharpe Ratio**: ${sharpe}
- **Beta**: ${beta}
- **Max Drawdown**: ${maxDrawdown}

## Portfolio Holdings Concentration
- **Top 5 Holdings**:
${topHoldingsMarkdown}
- **Major Sector Exposure**: N/A from current payload

## Detailed Analyst Report
${detailedAnalysis}

## Analyst Recommendation
${recommendation}

**HITL Status:** ${hitlStatus}`;

const requiredHeaders = [
  '# Mutual Fund Investment Report:',
  '## Executive Summary',
  '## Fund Profile',
  '## Performance Metrics',
  '## Risk & Volatility Analysis',
  '## Portfolio Holdings Concentration',
  '## Analyst Recommendation',
];
const hasRequiredHeaders = requiredHeaders.every((header) => reportMarkdown.includes(header));
const reportComplete = Boolean(agentOutput.trim()) && hasRequiredHeaders;

const fallbackMarkdown = `# Mutual Fund Investment Report: ${fundName}

## Executive Summary
A safe fallback was generated because the formatter did not receive a complete analyst report.

## Fund Profile
- **ISIN**: ${isin} | **AMC**: ${amcName}
- **Category**: ${category} | **Total AUM**: ${aum} Lakhs
- **Expense Ratio**: ${expenseRatio}

## Performance Metrics
- **1-Year CAGR**: ${cagr1y}
- **3-Year CAGR**: ${cagr3y}
- **5-Year CAGR**: ${cagr5y}

## Risk & Volatility Analysis
- **Standard Deviation**: ${stdDev}
- **Sharpe Ratio**: ${sharpe}
- **Beta**: ${beta}
- **Max Drawdown**: ${maxDrawdown}

## Portfolio Holdings Concentration
- **Top 5 Holdings**:
${topHoldingsMarkdown}
- **Major Sector Exposure**: N/A

## Analyst Recommendation
Fallback report generated due to missing or malformed analyst output.

**HITL Status:** DIRECT_ACTION`;

const finalMarkdown = reportComplete ? reportMarkdown : fallbackMarkdown;

// ---------- Slack blocks (bounded to Slack limits) ----------
const slackFallbackText = `${fundName} | ISIN ${isin} | 3Y CAGR ${cagr3y} | Sharpe ${sharpe} | Risk ${riskFlagText}`;
const slackBlocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: truncate(`Mutual Fund Report: ${fundName}`, 150), emoji: true },
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*ISIN:* ${isin}\n*AMC:* ${amcName}\n*Category:* ${category}\n*AUM:* ${aum} Lakhs\n*Expense Ratio:* ${expenseRatio}`,
    },
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*1Y CAGR*\n${cagr1y}` },
      { type: 'mrkdwn', text: `*3Y CAGR*\n${cagr3y}` },
      { type: 'mrkdwn', text: `*5Y CAGR*\n${cagr5y}` },
      { type: 'mrkdwn', text: `*Sharpe*\n${sharpe}` },
      { type: 'mrkdwn', text: `*Std Dev*\n${stdDev}` },
      { type: 'mrkdwn', text: `*Beta*\n${beta}` },
    ],
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Executive Summary*\n${truncate(execSummary, 2800)}` },
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Top Holdings*\n${topHoldingsSlack}` },
  },
  {
    type: 'context',
    elements: [
      { type: 'mrkdwn', text: `*Risk Flags:* ${sanitize(riskFlagText)} | *NAV Window:* ${navWindow}` },
    ],
  },
];

return [{
  json: {
    ...fundData,
    query: query,
    scheme_id: fundData.scheme_id ?? fundData.scheme_code,
    scheme_name: fundData.scheme_name || fundData.name,
    isin,
    amc_name: amcName,
    category,
    enriched: fundData.enriched,
    aum: fundData.aum,
    expense_ratio: fundData.expense_ratio,
    isValid: true,
    error: '',
    data: {
      nav_history: navHistory,
      holdings,
      risk_metrics: riskMetrics,
    },
    reportMarkdown: finalMarkdown,
    emailSubject: `Mutual Fund Investment Report: ${fundName}`,
    slackFallbackText,
    slackBlocks: JSON.stringify(slackBlocks),
    deliveryMeta: {
      hasRequiredHeaders,
      reportComplete,
      riskFlags,
      hitlStatus,
      usedFallback: !reportComplete,
      parsedMetrics: { cagr1y, cagr3y, cagr5y, stdDev, sharpe, beta, maxDrawdown },
    },
  },
}];

const report = $('Format Final Report').first().json || {};
const emailResult = $('Send Email Report').first().json || {};
const fundName = report.scheme_name || report.name || 'the fund';

let recipients = '';
if (Array.isArray(emailResult.accepted) && emailResult.accepted.length) {
  recipients = emailResult.accepted.join(', ');
} else if (emailResult.envelope && Array.isArray(emailResult.envelope.to) && emailResult.envelope.to.length) {
  recipients = emailResult.envelope.to.join(', ');
}

const sentLine = recipients
  ? `I've also emailed this full report to ${recipients}.`
  : "I've also emailed this full report to the configured recipient.";

const markdown = report.reportMarkdown || '_No report content was generated._';

const message = `Here is your mutual fund analysis for **${fundName}**.\n\n${sentLine}\n\n---\n\n${markdown}`;

return [{ json: { output: message } }];
